class MapSum:
    def __init__(self):
        self.t={}
    def insert(self, key, val):
        node=self.t; d=val-(self._get(key) if self._get(key) else 0)
        for c in key:
            node=node.setdefault(c,{"v":0,"c":{}})
            node["v"]+=d; node=node["c"]
        self._kv=key; self._vv=val
    def _get(self,k):
        return self._vv if getattr(self,"_kv",None)==k else 0
    def sum(self, prefix):
        node=self.t
        for c in prefix:
            if c not in node: return 0
            node=node[c]
        return node.get("v",0)

