class MapSum {
    struct Node{ int v=0; unordered_map<char,Node*> ch; };
    Node* rt=new Node(); unordered_map<string,int> mp;
public:
    void insert(string k,int val){ int d=val-(mp.count(k)?mp[k]:0); mp[k]=val; Node* cur=rt;
        for(char c:k){ if(!cur->ch[c]) cur->ch[c]=new Node(); cur=cur->ch[c]; cur->v+=d; } }
    int sum(string p){ Node* cur=rt; for(char c:p){ if(!cur->ch.count(c)) return 0; cur=cur->ch[c]; } return cur->v; }
};

